def get_integer_in_range(prompt, low, high):
    while True:
        try:
            value = int(input(prompt))
        except ValueError:
            print(f"  Please enter a whole number.")
            continue

        if low <= value <= high:
            return value
        else:
            print(f"  Number must be between {low} and {high}.")

